using System.Collections.Generic;\nusing UnityEngine;\n\npublic class LocalizationManager : MonoBehaviour\n{\n    public enum Language { English, Arabic }\n    private Language currentLanguage;\n\n    private Dictionary<string, string> localizedText;\n\n    void Awake() {\n        currentLanguage = Language.English; // Default to English\n        LoadLocalizedText();\n    }\n\n    void LoadLocalizedText() {\n        localizedText = new Dictionary<string, string>();\n        if (currentLanguage == Language.Arabic) {\n            localizedText.Add("greeting", "مرحبا"); // Arabic\n            localizedText.Add("goodbye", "وداعا"); // Arabic\n        } else {\n            localizedText.Add("greeting", "Hello"); // English\n            localizedText.Add("goodbye", "Goodbye"); // English\n        }\n    }\n\n    public string GetLocalizedText(string key) {\n        return localizedText[key];\n    }\n\n    public void ChangeLanguage(Language newLanguage) {\n        currentLanguage = newLanguage;\n        LoadLocalizedText();\n    }\n}